policies:
@rule_id("base_permit")
permit (principal, action, resource);
@tier("hard") @rule_id("rm_slash")
forbid (principal, action == Agent::Action::"execute_bash", resource) when { context.command like "*rm -rf /*" };
@tier("soft") @rule_id("force_push_any") @approval_timeout_s("300") @severity("medium") @category("destructive")
forbid (principal, action == Agent::Action::"execute_bash", resource) when { context.command like "*git push --force*" };
@tier("soft") @rule_id("force_push_main") @approval_timeout_s("600") @severity("high") @category("destructive")
forbid (principal, action == Agent::Action::"execute_bash", resource) when { context.command like "*git push --force origin main*" };
@tier("soft") @rule_id("write_env_files") @approval_timeout_s("600") @severity("high") @category("filesystem")
forbid (principal, action == Agent::Action::"write_file", resource) when { context.file_path like "*.env" };
